    public static void main(String[] args) {
        System.out.println("Testing Frequency fix...");

        // Test 1: Adding a non-comparable object should throw ClassCastException
        System.out.println("Test 1: Adding non-comparable object");
        Frequency freq = new Frequency();
        try {
            Object nonComparable = new Object(); // Object doesn't implement Comparable
            freq.addValue(nonComparable); // This should throw ClassCastException
            System.out.println("ERROR: Expected ClassCastException but none was thrown");
        } catch (ClassCastException e) {
            System.out.println("SUCCESS: Got expected ClassCastException: " + e.getMessage());
        } catch (Exception e) {
            System.out.println("ERROR: Got unexpected exception: " + e.getClass().getSimpleName() + " - " + e.getMessage());
        }

        // Test 2: Adding compatible objects should work
        System.out.println("\nTest 2: Adding compatible comparable objects");
        try {
            freq.addValue("string1"); // This should work
